{
  "name": "flashcards-express-tailwind",
  "version": "0.1.0",
  "private": true,
  "description": "Minimal Express + Tailwind starter for a flash card app",
  "scripts": {
    "dev": "concurrently -n server,css -c red,black -k \"nodemon src/server.js\" \"tailwindcss -i ./src/styles/input.css -o ./public/styles.css --watch\"",
    "start": "node src/server.js",
    "build:css": "tailwindcss -i ./src/styles/input.css -o ./public/styles.css --minify",
    "test": "node --test"
  },
  "dependencies": {
    "cors": "^2.8.5",
    "express": "^4.19.2",
    "uuid": "^9.0.1"
  },
  "devDependencies": {
    "autoprefixer": "^10.4.18",
    "concurrently": "^9.0.0",
    "nodemon": "^3.0.1",
    "postcss": "^8.4.47",
    "tailwindcss": "^3.4.14"
  },
  "engines": {
    "node": ">=18"
  }
}

'use strict';
const express = require('express');
const cors = require('cors');
const path = require('path');

const PORT = process.env.PORT ? Number(process.env.PORT) : 4566;
const app = express();

app.use(cors());
app.use(express.json());

// Serve static files
app.use(express.static(path.join(__dirname, '..', 'public')));

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body { @apply bg-white text-black; }
}

const colors = require('tailwindcss/colors');

module.exports = {
  content: [
    './public/**/*.html',
    './src/**/*.js'
  ],
  theme: {
    colors: {
      transparent: 'transparent',
      current: 'currentColor',
      red: colors.red,
      black: '#000000',
      white: '#ffffff'
    },
    extend: {}
  },
  plugins: []
};

const test = require('node:test');
const assert = require('node:assert');
const pkg = require('../package.json');

test('package.json has required scripts', () => {
  assert.ok(pkg.scripts, 'scripts field missing');
  assert.ok(pkg.scripts.dev, 'dev script missing');
  assert.ok(pkg.scripts.start, 'start script missing');
  assert.ok(pkg.scripts['build:css'], 'build:css script missing');
});

test('dependencies include express, cors, uuid', () => {
  const deps = pkg.dependencies || {};
  assert.ok(deps.express, 'express not listed in dependencies');
  assert.ok(deps.cors, 'cors not listed in dependencies');
  assert.ok(deps.uuid, 'uuid not listed in dependencies');
});

test('devDependencies include tailwind, postcss, autoprefixer, nodemon, concurrently', () => {
  const dev = pkg.devDependencies || {};
  assert.ok(dev.tailwindcss, 'tailwindcss not listed in devDependencies');
  assert.ok(dev.postcss, 'postcss not listed in devDependencies');
  assert.ok(dev.autoprefixer, 'autoprefixer not listed in devDependencies');
  assert.ok(dev.nodemon, 'nodemon not listed in devDependencies');
  assert.ok(dev.concurrently, 'concurrently not listed in devDependencies');
});
